// v4 - Cluster Overview Collection
import groovy.json.JsonSlurper

class ThanosClient {
    private String host, token, baseUrl
    private int port
    private boolean ssl

    ThanosClient(Map p) {
        this.host = p.get("kubevirt.thanos.host")
        this.token = p.get("kubevirt.thanos.token")
        this.port = (p.get("kubevirt.thanos.port") ?: "443") as int
        this.ssl = (p.get("kubevirt.thanos.ssl") ?: "true").toLowerCase() == "true"
        if (!host || !token) throw new IllegalArgumentException("Missing config")
        def proto = ssl ? "https" : "http"
        def ps = ((ssl && port == 443) || (!ssl && port == 80)) ? "" : ":${port}"
        this.baseUrl = "${proto}://${host}${ps}"
    }

    def query(String promql) {
        def url = "${baseUrl}/api/v1/query?query=${java.net.URLEncoder.encode(promql, 'UTF-8')}"
        try {
            def resp = executeHttpGet(url)
            def json = new JsonSlurper().parseText(resp)
            if (json.status != "success") return null
            return json
        } catch (Exception e) { return null }
    }

    private String executeHttpGet(String url) {
        try {
            def http = Class.forName("com.santaba.agent.groovyapi.http.HTTP").newInstance()
            http.open(url); http.setHeader("Authorization", "Bearer ${token}")
            def r = http.get(); http.close(); return r
        } catch (ClassNotFoundException e) {
            def c = new URL(url).openConnection() as HttpURLConnection
            c.setRequestMethod("GET"); c.setRequestProperty("Authorization", "Bearer ${token}")
            c.setConnectTimeout(30000); c.setReadTimeout(60000)
            if (ssl) { try {
                def sc = javax.net.ssl.SSLContext.getInstance("TLS")
                sc.init(null, [new javax.net.ssl.X509TrustManager() {
                    void checkClientTrusted(java.security.cert.X509Certificate[] x, String a) {}
                    void checkServerTrusted(java.security.cert.X509Certificate[] x, String a) {}
                    java.security.cert.X509Certificate[] getAcceptedIssuers() { null }
                }] as javax.net.ssl.TrustManager[], new java.security.SecureRandom())
                c.setSSLSocketFactory(sc.getSocketFactory()); c.setHostnameVerifier({ h, s -> true })
            } catch (Exception ex) {} }
            if (c.getResponseCode() != 200) throw new RuntimeException("HTTP ${c.getResponseCode()}")
            return c.getInputStream().text
        }
    }
}

try {
    def client = new ThanosClient(hostProps)
    def metrics = [
        "vms_total": 'sum(kubevirt_number_of_vms)',
        "vms_running": 'count(kubevirt_vmi_phase_count{phase="running"})',
        "allocatable_nodes": 'kubevirt_allocatable_nodes',
        "nodes_with_kvm": 'kubevirt_nodes_with_kvm',
        "virt_api_up": 'kubevirt_virt_api_up',
        "virt_controller_up": 'kubevirt_virt_controller_up',
        "virt_handler_up": 'kubevirt_virt_handler_up',
        "system_health": 'kubevirt_hco_system_health_status',
        "migrations_pending": 'sum(kubevirt_vmi_migrations_in_pending_phase)',
        "migrations_running": 'sum(kubevirt_vmi_migrations_in_running_phase)',
        "migrations_scheduling": 'sum(kubevirt_vmi_migrations_in_scheduling_phase)'
    ]
    metrics.each { dp, q ->
        def json = client.query(q)
        if (json && json.data?.result?.size() > 0) {
            def val = json.data.result[0].value[1]
            if (val != null) println "${dp}=${val}"
        }
    }
    return 0
} catch (Exception e) {
    System.err.println "ERROR: ${e.message}"
    return 1
}
